<?php
declare(strict_types=1);
require_once __DIR__.'/../../config/config.php'; require_once ROOT_PATH.'/functions/vehicle_functions.php'; requireAuth(); enforceModuleAccess('vehicles');
$id=(int)($_GET['id']??$_POST['id']??0); $vehicle=getVehicleById($id); if(!$vehicle){setFlash('danger','Vehicle not found.');redirect('modules/vehicles/index.php');}
if($_SERVER['REQUEST_METHOD']==='POST'){try{if(!verifyCsrfToken((string)($_POST['csrf_token']??'')))throw new RuntimeException('Your form session expired.');updateVehicle($id,$_POST);setFlash('success','Vehicle updated successfully.');redirect('modules/vehicles/view.php?id='.$id);}catch(Throwable $e){setFlash('danger',$e->getMessage());$vehicle=array_merge($vehicle,$_POST);}}
$types=getDb()->query('SELECT id,name FROM vehicle_types ORDER BY name')->fetchAll();$regions=getDb()->query('SELECT id,name FROM regions ORDER BY name')->fetchAll();$pageTitle='Edit vehicle';require ROOT_PATH.'/includes/header.php';require ROOT_PATH.'/includes/sidebar.php';
?><main class="main-content"><?php require ROOT_PATH.'/includes/navbar.php';?><section class="page-section"><form class="card dashboard-card" method="post"><input type="hidden" name="csrf_token" value="<?=e(csrfToken())?>"><input type="hidden" name="id" value="<?=$id?>"><h1 class="page-title">Edit <?=e($vehicle['registration_number'])?></h1><p class="page-subtitle">Registration number remains immutable after onboarding.</p><div class="form-grid"><div class="form-group"><label>Registration number</label><input value="<?=e($vehicle['registration_number'])?>" disabled><input type="hidden" name="registration_number" value="<?=e($vehicle['registration_number'])?>"></div><?php foreach(['vehicle_name'=>'Vehicle name','make'=>'Make','model'=>'Model','year'=>'Year','capacity_kg'=>'Capacity (kg)','current_odometer_km'=>'Odometer (km)','purchase_date'=>'Purchase date','purchase_cost'=>'Purchase cost','insurance_number'=>'Insurance number','insurance_expiry'=>'Insurance expiry','fitness_expiry'=>'Fitness expiry','permit_expiry'=>'Permit expiry','pollution_expiry'=>'Pollution expiry'] as $field=>$label):?><div class="form-group"><label><?=e($label)?></label><input name="<?=$field?>" type="<?=str_contains($field,'date')||str_contains($field,'expiry')?'date':(in_array($field,['year','capacity_kg','current_odometer_km','purchase_cost'],true)?'number':'text')?>" value="<?=e((string)($vehicle[$field]??''))?>" <?=in_array($field,['vehicle_name','make','model','year','capacity_kg','current_odometer_km','purchase_cost'],true)?'required':''?>></div><?php endforeach;?><div class="form-group"><label>Type</label><select name="vehicle_type_id"><?php foreach($types as $type):?><option value="<?=$type['id']?>"<?=$vehicle['vehicle_type_id']==$type['id']?' selected':''?>><?=e($type['name'])?></option><?php endforeach;?></select></div><div class="form-group"><label>Region</label><select name="region_id"><?php foreach($regions as $region):?><option value="<?=$region['id']?>"<?=$vehicle['region_id']==$region['id']?' selected':''?>><?=e($region['name'])?></option><?php endforeach;?></select></div><div class="form-group"><label>Fuel type</label><select name="fuel_type"><?php foreach(['Diesel','Petrol','CNG','Electric'] as $fuel):?><option<?=$vehicle['fuel_type']===$fuel?' selected':''?>><?=e($fuel)?></option><?php endforeach;?></select></div><div class="form-group"><label>Status</label><select name="status"><?php foreach(['Available','In Shop','Retired','Sold'] as $status):?><option<?=$vehicle['status']===$status?' selected':''?>><?=e($status)?></option><?php endforeach;?></select></div></div><div class="form-group"><label>Remarks</label><textarea name="remarks"><?=e((string)($vehicle['remarks']??''))?></textarea></div><div class="form-actions"><button class="btn btn-primary">Save changes</button><a class="btn btn-secondary" href="view.php?id=<?=$id?>">Cancel</a></div></form></section></main><?php require ROOT_PATH.'/includes/footer.php';?>
